# Semantic schema v2: explicit structure assembly + standalone detail safety flags.
ASHLAND_B_SEMANTIC_SCHEMA_VERSION = 2


def _b_id(col: int, row: int) -> str:
    entry = ASHLAND_B_MANIFEST.get(f"{col},{row}")
    if not isinstance(entry, dict):
        return ""
    return str(entry.get("id", ""))


def _b_role(dx: int, dy: int, width: int, height: int) -> str:
    if dx == 0 and dy == 0:
        return "top_left"
    if dx == width - 1 and dy == 0:
        return "top_right"
    if dx == 0 and dy == height - 1:
        return "bottom_left"
    if dx == width - 1 and dy == height - 1:
        return "bottom_right"
    if dy == 0:
        return "top"
    if dy == height - 1:
        return "bottom"
    if dx == 0:
        return "left"
    if dx == width - 1:
        return "right"
    return "center"


def _b_build_structure_cells(
    *,
    start_col: int,
    start_row: int,
    width: int,
    height: int,
) -> list[dict[str, object]]:
    cells: list[dict[str, object]] = []
    for dy in range(height):
        for dx in range(width):
            tile_id = _b_id(start_col + dx, start_row + dy)
            if not tile_id:
                continue
            cells.append(
                {
                    "dx": dx,
                    "dy": dy,
                    "tile_id": tile_id,
                    "structure_role": _b_role(dx, dy, width, height),
                }
            )
    return cells


