def _b_build_border_groups() -> dict[str, tuple[str, ...]]:
    coord_to_group = {
        tuple(entry["coord"]): str(entry["group"]) for entry in ASHLAND_B_MANIFEST.values()
    }
    borders_by_tile_id: dict[str, tuple[str, ...]] = {}
    for entry in ASHLAND_B_MANIFEST.values():
        col, row = entry["coord"]
        groups: set[str] = set()
        for d_col, d_row in ((1, 0), (-1, 0), (0, 1), (0, -1)):
            neighbor = coord_to_group.get((col + d_col, row + d_row))
            if neighbor is not None:
                groups.add(neighbor)
        borders_by_tile_id[str(entry["id"])] = tuple(sorted(groups))
    return borders_by_tile_id


ASHLAND_B_TILE_BORDER_GROUPS = _b_build_border_groups()

ASHLAND_B_TILE_STRUCTURE_MEMBERSHIP: dict[str, list[dict[str, object]]] = {}
for _template in ASHLAND_B_STRUCTURE_TEMPLATES:
    for _cell in _template["cells"]:
        _tile_id = str(_cell["tile_id"])
        ASHLAND_B_TILE_STRUCTURE_MEMBERSHIP.setdefault(_tile_id, []).append(
            {
                "structure_id": _template["structure_id"],
                "structure_group": _template["structure_group"],
                "structure_role": _cell["structure_role"],
                "footprint": _template["footprint"],
            }
        )

ASHLAND_B_TILE_SELECTION_FLAGS: dict[str, dict[str, object]] = {}
for _entry in ASHLAND_B_MANIFEST.values():
    _tile_id = str(_entry["id"])
    _group = str(_entry["group"])
    _borders_groups = ASHLAND_B_TILE_BORDER_GROUPS.get(_tile_id, ())
    _structure_memberships = ASHLAND_B_TILE_STRUCTURE_MEMBERSHIP.get(_tile_id, [])
    _can_standalone = _tile_id in ASHLAND_B_STANDALONE_TILE_IDS

    _exclude_reasons: list[str] = []
    if _group in ASHLAND_B_SELECTION_EXCLUDED_GROUPS:
        _exclude_reasons.append("excluded_group")
    if not _can_standalone and not _structure_memberships:
        _exclude_reasons.append("uncurated_fragment_or_empty")
    if "empty" in _borders_groups and not _structure_memberships:
        _exclude_reasons.append("borders_empty_group")

    ASHLAND_B_TILE_SELECTION_FLAGS[_tile_id] = {
        "group": _group,
        "group_role": ASHLAND_B_GROUP_ROLES.get(_group, "unknown"),
        "borders_groups": list(_borders_groups),
        "exclude_from_detail_selection": bool(_exclude_reasons),
        "exclude_reasons": _exclude_reasons,
        "can_place_standalone": _can_standalone,
        "structure_memberships": _structure_memberships,
    }

ASHLAND_B_UNCERTAIN_TILE_IDS = sorted(
    tile_id
    for tile_id, payload in ASHLAND_B_TILE_SELECTION_FLAGS.items()
    if "uncurated_fragment_or_empty" in payload["exclude_reasons"]
    and payload["group"] not in ASHLAND_B_SELECTION_EXCLUDED_GROUPS
)
